        p.rts_flags.store(0, Ordering::Relaxed);

        let _ = writeln!(
            Pl011::new(),
            "[as] vm nr={} ttbr0_pa={:#x} asid={} entry={:#x}",
            p.nr.get(),
            p.ttbr0_pa,
            p.asid,
