```rust
pub unsafe fn load_boot_servers(servers: &[(ProcNr, &'static [u8])]) {
    for (proc_nr, elf_bytes) in servers {
        // 1. Allocate AddrSpace
        let mut aspace = AddrSpace::new().expect("AddrSpace::new");
        let ttbr0_pa = aspace.ttbr0_pa;

        // 2. Load ELF, get entry point
        let entry = crate::boot_image::elf::load_into(elf_bytes, &mut aspace)
            .expect("ELF load failed");

        // 3. Allocate + map stack
        let stack_frame = alloc_frame().expect("stack frame alloc");
        aspace
            .map_page(STACK_VA_FOR_SERVER, stack_frame.addr(), Prot::RW_DATA)
            .expect("map_page(stack)");

        // 4. Allocate ASID
        let asid = unsafe { alloc_asid() };

        // 5. Write proc slot: registers, ttbr0_pa, asid, endpoint, rts_flags=0
        unsafe {
            let p = proc_slot_mut(proc_nr).expect("proc slot");
            p.regs.elr_el1 = entry;
            p.regs.sp_el0 = STACK_VA_FOR_SERVER + PAGE_SIZE as u64;
            p.regs.spsr_el1 = STUB_SPSR_EL0;
            p.ttbr0_pa = ttbr0_pa;
            p.asid = asid;
            p.next_ready = None;
            p.rts_flags.store(0, Ordering::Relaxed);  // Mark runnable
        }

        // 6. Forget aspace (tree ownership stays via ttbr0_pa)
        core::mem::forget(aspace);

        // 7. Enqueue
        unsafe { sched::enqueue(proc_nr) };
    }
}
```

**Assumptions:**
- All boot servers already have proc slots populated by `init_boot_image()` (name, priority, priv_id, endpoint)
- Stack VA can be derived from `proc_nr` (or passed per-server)
- All servers fit the "load ELF + allocate stack" pattern

