1	// SPDX-License-Identifier: BSD-3-Clause
2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	//! Minimal static aarch64 ELF64 loader.
4	//!
5	//! Just enough to bring up the VM server (slice 3.4): parse the ELF header,
6	//! walk the program headers, and map each `PT_LOAD` segment into a freshly
7	//! built [`AddrSpace`]. No dynamic relocations, no interpreter, no symbol
8	//! resolution — the user binaries are statically linked `ET_EXEC` images
9	//! produced by `servers/*/user.ld`, which keeps every segment page-aligned
10	//! (vaddr *and* file offset) so this loader never has to split a page across
11	//! two segments.
12	//!
13	//! All field reads are explicit little-endian (`from_le_bytes`) because the
14	//! ELF bytes are embedded via `include_bytes!` and carry no alignment
15	//! guarantee. Frames come from the slice-3.1a allocator (zeroed on hand-out,
16	//! so a segment's BSS tail is satisfied for free) and are copied into via
17	//! HHDM, mirroring `userland::build_stub`'s stub-blob copy.
18	
19	use crate::arch::aarch64::addrspace::{AddrSpace, MapError, Prot};
20	use crate::arch::aarch64::mmu::{PAGE_SIZE, flush_icache_range};
21	use crate::mm::{alloc_frame, phys_to_hhdm};
22	
23	/// Errors the loader can surface. All are fatal at boot (the embedded VM ELF
24	/// is produced by our own build, so any of these means a build/loader bug).
25	#[derive(Copy, Clone, Debug, PartialEq, Eq)]
26	pub enum ElfError {
27	    /// Too few bytes for the ELF header or a program header table entry.
28	    Truncated,
29	    /// `e_ident` magic is not `\x7fELF`.
30	    BadMagic,
31	    /// Not `ELFCLASS64`.
32	    BadClass,
33	    /// Not little-endian (`ELFDATA2LSB`).
34	    BadData,
35	    /// `e_machine` is not `EM_AARCH64`.
36	    BadMachine,
37	    /// `e_type` is not `ET_EXEC`.
38	    BadType,
39	    /// `e_phentsize` is not the expected 56 bytes.
40	    BadPhentsize,
41	    /// A `PT_LOAD` segment is not page-aligned (vaddr or file offset), or its
42	    /// file span exceeds its memory span.
43	    Misaligned,
44	    /// A segment requested both write and execute permission (W^X violation).
45	    WriteExec,
46	    /// The address-space mapping failed (out of memory, already mapped, …).
47	    Map(MapError),
48	}
49	
50	impl From<MapError> for ElfError {
51	    fn from(e: MapError) -> Self {
52	        ElfError::Map(e)
53	    }
54	}
55	
56	// ELF identification / header field offsets and constants (Elf64).
57	const EI_CLASS: usize = 4;
58	const EI_DATA: usize = 5;
59	const ELFCLASS64: u8 = 2;
60	const ELFDATA2LSB: u8 = 1;
61	const EM_AARCH64: u16 = 0xB7;
62	const ET_EXEC: u16 = 2;
63	const EHDR_SIZE: usize = 64;
64	const PHDR_SIZE: usize = 56;
65	
66	const PT_LOAD: u32 = 1;
67	const PF_X: u32 = 1;
68	const PF_W: u32 = 2;
69	
70	fn rd_u16(b: &[u8], off: usize) -> Result<u16, ElfError> {
71	    b.get(off..off + 2)
72	        .map(|s| u16::from_le_bytes([s[0], s[1]]))
73	        .ok_or(ElfError::Truncated)
74	}
75	
76	fn rd_u32(b: &[u8], off: usize) -> Result<u32, ElfError> {
77	    b.get(off..off + 4)
78	        .map(|s| u32::from_le_bytes([s[0], s[1], s[2], s[3]]))
79	        .ok_or(ElfError::Truncated)
80	}
81	
82	fn rd_u64(b: &[u8], off: usize) -> Result<u64, ElfError> {
83	    b.get(off..off + 8)
84	        .map(|s| u64::from_le_bytes([s[0], s[1], s[2], s[3], s[4], s[5], s[6], s[7]]))
85	        .ok_or(ElfError::Truncated)
86	}
87	
88	/// Load every `PT_LOAD` segment of `elf` into `aspace` and return the entry
89	/// point virtual address (`e_entry`).
90	pub fn load_into(elf: &[u8], aspace: &mut AddrSpace) -> Result<u64, ElfError> {
91	    if elf.len() < EHDR_SIZE {
92	        return Err(ElfError::Truncated);
93	    }
94	    if elf[0..4] != [0x7f, b'E', b'L', b'F'] {
95	        return Err(ElfError::BadMagic);
96	    }
97	    if elf[EI_CLASS] != ELFCLASS64 {
98	        return Err(ElfError::BadClass);
99	    }
100	    if elf[EI_DATA] != ELFDATA2LSB {
101	        return Err(ElfError::BadData);
102	    }
103	    if rd_u16(elf, 16)? != ET_EXEC {
104	        return Err(ElfError::BadType);
105	    }
106	    if rd_u16(elf, 18)? != EM_AARCH64 {
107	        return Err(ElfError::BadMachine);
108	    }
109	
110	    let e_entry = rd_u64(elf, 24)?;
111	    let e_phoff = rd_u64(elf, 32)? as usize;
112	    let e_phentsize = rd_u16(elf, 54)? as usize;
113	    let e_phnum = rd_u16(elf, 56)? as usize;
114	    if e_phentsize != PHDR_SIZE {
115	        return Err(ElfError::BadPhentsize);
116	    }
117	
118	    for i in 0..e_phnum {
119	        let ph = e_phoff + i * e_phentsize;
120	        if rd_u32(elf, ph)? != PT_LOAD {
121	            continue;
122	        }
123	        let p_flags = rd_u32(elf, ph + 4)?;
124	        let p_offset = rd_u64(elf, ph + 8)? as usize;
125	        let p_vaddr = rd_u64(elf, ph + 16)?;
126	        let p_filesz = rd_u64(elf, ph + 32)? as usize;
127	        let p_memsz = rd_u64(elf, ph + 40)? as usize;
128	
129	        load_segment(elf, aspace, p_flags, p_offset, p_vaddr, p_filesz, p_memsz)?;
130	    }
131	
132	    Ok(e_entry)
133	}
134	
135	#[allow(clippy::too_many_arguments)]
136	fn load_segment(
137	    elf: &[u8],
138	    aspace: &mut AddrSpace,
139	    p_flags: u32,
140	    p_offset: usize,
141	    p_vaddr: u64,
142	    p_filesz: usize,
143	    p_memsz: usize,
144	) -> Result<(), ElfError> {
145	    // Page-aligned segments keep the per-page copy below trivial. Bit-and
146	    // alignment check mirrors `addrspace::check_va`'s idiom.
147	    let page_mask = PAGE_SIZE as u64 - 1;
148	    if p_vaddr & page_mask != 0 || (p_offset as u64) & page_mask != 0 || p_filesz > p_memsz {
149	        return Err(ElfError::Misaligned);
150	    }
151	    // The file region must actually be present in the embedded image.
152	    if p_offset
153	        .checked_add(p_filesz)
154	        .map(|e| e > elf.len())
155	        .unwrap_or(true)
156	    {
157	        return Err(ElfError::Truncated);
158	    }
159	
160	    let writable = p_flags & PF_W != 0;
161	    let executable = p_flags & PF_X != 0;
162	    if writable && executable {
163	        return Err(ElfError::WriteExec);
164	    }
165	    let prot = match (writable, executable) {
166	        (false, true) => Prot::RO_CODE,
167	        (true, false) => Prot::RW_DATA,
168	        (false, false) => Prot::RO_DATA,
169	        (true, true) => unreachable!("W^X checked above"),
170	    };
171	
172	    let n_pages = p_memsz.div_ceil(PAGE_SIZE);
173	    for page_idx in 0..n_pages {
174	        let va = p_vaddr + (page_idx * PAGE_SIZE) as u64;
175	        let frame = alloc_frame().ok_or(ElfError::Map(MapError::OutOfMemory))?;
176	
177	        // Copy this page's slice of file data; the rest of the frame stays
178	        // zero (BSS tail). `file_page_start` is the byte offset within the
179	        // segment, not the file.
180	        let file_page_start = page_idx * PAGE_SIZE;
181	        let copy_len = p_filesz.saturating_sub(file_page_start).min(PAGE_SIZE);
182	        if copy_len > 0 {
183	            let src = &elf[p_offset + file_page_start..p_offset + file_page_start + copy_len];
184	            // SAFETY: `frame` was just allocated (exclusively ours, zeroed, and
185	            // HHDM-mapped); `src` is a bounds-checked subslice of the embedded
186	            // ELF. Disjoint regions, `copy_len <= PAGE_SIZE`.
187	            unsafe {
188	                let dst = phys_to_hhdm(frame.addr());
189	                core::ptr::copy_nonoverlapping(src.as_ptr(), dst, copy_len);
190	                if executable {
191	                    flush_icache_range(dst as u64, copy_len);
192	                }
193	            }
194	        }
195	
196	        aspace.map_page(va, frame.addr(), prot)?;
197	    }
198	
199	    Ok(())
200	}
201

