1	// SPDX-License-Identifier: BSD-3-Clause
2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	//! Slice-3.1b userland bootstrap: per-process address spaces with 8-bit
4	//! ARMv8 ASIDs.
5	//!
6	//! Each of the three EL0 stubs (A, B, C — the slice 2.5 / 2.6 regression
7	//! coverage) gets its own [`AddrSpace`] built from the slice-3.1a frame
8	//! allocator. Code and stack pages are allocated as fresh frames, the
9	//! stub blob is copied in via HHDM (`mm::phys_to_hhdm`), and the
10	//! resulting `(ttbr0_pa, asid)` is stored on the proc slot. The scheduler
11	//! ([`crate::proc::sched::schedule_next`]) installs that TTBR0 on every
12	//! EL1 → EL0 transition.
13	//!
14	//! What slice 3.1a's smoke test exercised in isolation — `AddrSpace::new`,
15	//! `map_page`, `walk_pt`, the free-list reuse on `destroy` — now drives
16	//! the three real EL0 stubs.
17	//!
18	//! What this slice does *not* do:
19	//!   - Recover from page faults. EC=0x20 / EC=0x24 still panic via
20	//!     [`super::exception::el0_sync_unexpected`]; slice 3.1b extends that
21	//!     handler's ISS decoder so the dump is informative, but the policy
22	//!     is still "halt" — real `do_page_fault` + `RTS_PAGEFAULT` land in
23	//!     slice 3.2.
24	//!   - Cross-AS IPC delivery. The SVC handler runs in the caller's TTBR0,
25	//!     so single-AS reads in `ipc::message` still walk correctly; slice
26	//!     3.4's HHDM-walk redesign of `flush_deliver_msg` swaps that out
27	//!     once VM exists.
28	//!   - Install a kernel-shared global mapping for the EL0 stubs. The
29	//!     code page is mapped RO + EL0-executable into each per-proc AS
30	//!     individually (zero shared frames).
31	
32	use core::sync::atomic::Ordering;
33	
34	use minixrs_kernel_shared::callnr::{KERNEL_CALL, SYS_GETINFO};
35	use minixrs_kernel_shared::com::{RS_PROC_NR, SYSTEM, VM_PROC_NR, boot_endpoint};
36	use minixrs_kernel_shared::{PrivId, ProcNr};
37	
38	use crate::arch::aarch64::addrspace::{AddrSpace, Prot};
39	use crate::arch::aarch64::asid::alloc_asid;
40	use crate::arch::aarch64::mmu::{self, PAGE_SIZE, flush_icache_range};
41	use crate::mm::{Frame, alloc_frame, phys_to_hhdm};
42	use crate::proc::bitmap::{set_call_bit, set_sys_bit};
43	use crate::proc::flags::{BILLABLE, PREEMPTIBLE, SRV_T, SYS_PROC, USR_T};
44	use crate::proc::sched;
45	use crate::proc::table::{priv_slot_mut, proc_index, proc_slot_mut, proc_table_ref};
46	use crate::proc::{HeapWindow, Priv, Proc};
47	
48	// ----- EL0 virtual addresses ------------------------------------------------
49	
50	/// VA at which stub A's code page is mapped.
51	pub const USER_CODE_VA_A: u64 = 0x0040_0000; // 4 MiB
52	/// VA at which stub A's stack page is mapped.
53	pub const USER_STACK_VA_A: u64 = 0x0080_0000; // 8 MiB
54	
55	/// VA at which stub B's code page is mapped.
56	pub const USER_CODE_VA_B: u64 = 0x0041_0000;
57	/// VA at which stub B's stack page is mapped.
58	pub const USER_STACK_VA_B: u64 = 0x0081_0000;
59	
60	/// VA at which stub C's code page is mapped.
61	pub const USER_CODE_VA_C: u64 = 0x0042_0000;
62	/// VA at which stub C's stack page is mapped.
63	pub const USER_STACK_VA_C: u64 = 0x0082_0000;
64	
65	/// VA at which stub D's code page is mapped.
66	pub const USER_CODE_VA_D: u64 = 0x0043_0000;
67	/// VA at which stub D's stack page is mapped.
68	pub const USER_STACK_VA_D: u64 = 0x0083_0000;
69	
70	// Stub D's heap VA (`0x0100_0000`) lives only in `user_stub.S`'s stub D blob
71	// and in the VM server's `region::HEAP_BASE` (slice 3.5): D issues `VM_BRK` to
72	// grow its heap, then touches it. The kernel needs no heap-window constant —
73	// faults route to VM, which gates them on its per-proc region table.
74	
75	/// First proc-table slot beyond the boot image — `ProcNr(11)`.
76	const STUB_A_PROC_NR: ProcNr = ProcNr::new(11);
77	/// Second stub slot, just after A.
78	const STUB_B_PROC_NR: ProcNr = ProcNr::new(12);
79	/// Slice-2.6 kernel-call client. Slot 13 — one past the slice-2.5 pair.
80	const STUB_C_PROC_NR: ProcNr = ProcNr::new(13);
81	/// Slice-3.2 page-fault demo. Slot 14.
82	const STUB_D_PROC_NR: ProcNr = ProcNr::new(14);
83	
84	/// Privilege-table slots for the four stubs. Boot image uses 0..=15;
85	/// 16, 17, 18, and 19 are the first free entries.
86	const STUB_A_PRIV_ID: PrivId = PrivId::new(16);
87	const STUB_B_PRIV_ID: PrivId = PrivId::new(17);
88	const STUB_C_PRIV_ID: PrivId = PrivId::new(18);
89	const STUB_D_PRIV_ID: PrivId = PrivId::new(19);
90	
91	// SPSR_EL1 to install on each stub's `eret`. Matches slice 2.4: IRQs
92	// unmasked at EL0 (bit 7 = 0), debug + SError + FIQ masked. EL0t.
93	const STUB_SPSR_EL0: u64 = 0x340;
94	
95	// ----- EL0 stub blobs (linked into the kernel image by `user_stub.S`) ------
96	
97	unsafe extern "C" {
98	    static _user_stub_a_start: u8;
99	    static _user_stub_a_end: u8;
100	    static _user_stub_b_start: u8;
101	    static _user_stub_b_end: u8;
102	    static _user_stub_c_start: u8;
103	    static _user_stub_c_end: u8;
104	    static _user_stub_d_start: u8;
105	    static _user_stub_d_end: u8;
106	}
107	
108	/// VA at which the VM server's stack page is mapped. Distinct from VM's ELF
109	/// segments (loaded from `0x0010_0000` up by `servers/vm/user.ld`) and from
110	/// every EL0 stub VA.
111	const VM_STACK_VA: u64 = 0x0020_0000; // 2 MiB
112	
113	// ----- Bootstrap ----------------------------------------------------------
114	
115	/// Build three per-process address spaces (one per EL0 stub), populate
116	/// their proc + priv slots, and enqueue them on the scheduler.
117	///
118	/// Compared to slice 2.5/2.6 this:
119	///   - Drops the static `L0_TABLE`/.../`L3_STACK_TABLE` + `USER_*_PAGE_*`
120	///     arrays. Every frame is allocated from `mm::alloc_frame`.
121	///   - Hands each stub its own `(ttbr0_pa, asid)` via
122	///     [`build_stub`] + [`AddrSpace`].
123	///   - No longer installs a single TTBR0 from boot context; the scheduler
124	///     installs per-proc TTBR0 + ASID on every EL1 → EL0 transition.
125	///
126	/// SAFETY: must be called exactly once from `kmain` after `proc::init`,
127	/// `mm::set_hhdm_offset`, and `mm::init_from_limine_memmap`. Single-
128	/// threaded boot context; no other reference into the named proc slots
129	/// or the frame allocator may be live concurrently.
130	pub unsafe fn userland_bootstrap() {
131	    // 1. Verify Limine left MAIR_EL1 + TCR_EL1 in the shape our walker
132	    //    + per-proc TTBR0 install expect. The slice-3.1b TCR_EL1.AS = 0
133	    //    assert was added inside `assert_tcr_el1_ttbr0_ready`.
134	    mmu::assert_mair_normal_wb();
135	    mmu::assert_tcr_el1_ttbr0_ready();
136	
137	    // 2. Clear TCR_EL1.EPD0 once. Per-proc TTBR0 install happens at every
138	    //    context switch via `proc::sched::schedule_next`.
139	    // SAFETY: DAIF still masked from Limine handoff; single-threaded boot.
140	    unsafe { mmu::enable_ttbr0_walks_once() };
141	
142	    // 2.5. Load the real VM server (slice 3.4) before the stubs so it takes
143	    //      ASID 1 and is enqueued first. Its `RECEIVE(ANY)` blocks immediately
144	    //      (no senders yet), leaving the run queue free for the band-8 stubs.
145	    // SAFETY: single-threaded boot; sole writer of VM's proc slot + allocator.
146	    unsafe { vm_bootstrap() };
147	
148	    // 3. Build each stub. Sequential calls — each build_stub allocates
149	    //    fresh frames + a fresh AddrSpace and writes its proc slot.
150	    // SAFETY: single-threaded boot; build_stub only touches its own
151	    // allocated state + the named proc slot.
152	    unsafe {
153	        build_stub(
154	            STUB_A_PROC_NR,
155	            STUB_A_PRIV_ID,
156	            b'A',
157	            &_user_stub_a_start,
158	            &_user_stub_a_end,
159	            USER_CODE_VA_A,
160	            USER_STACK_VA_A,
161	            HeapWindow::EMPTY,
162	        );
163	        build_stub(
164	            STUB_B_PROC_NR,
165	            STUB_B_PRIV_ID,
166	            b'B',
167	            &_user_stub_b_start,
168	            &_user_stub_b_end,
169	            USER_CODE_VA_B,
170	            USER_STACK_VA_B,
171	            HeapWindow::EMPTY,
172	        );
173	        build_stub(
174	            STUB_C_PROC_NR,
175	            STUB_C_PRIV_ID,
176	            b'C',
177	            &_user_stub_c_start,
178	            &_user_stub_c_end,
179	            USER_CODE_VA_C,
180	            USER_STACK_VA_C,
181	            HeapWindow::EMPTY,
182	        );
183	        build_stub(
184	            STUB_D_PROC_NR,
185	            STUB_D_PRIV_ID,
186	            b'D',
187	            &_user_stub_d_start,
188	            &_user_stub_d_end,
189	            USER_CODE_VA_D,
190	            USER_STACK_VA_D,
191	            // D issues `VM_BRK` to grow its heap and touches it (slice 3.5),
192	            // then `VM_MMAP`/`VM_MUNMAP` an anonymous region (slice 3.6). Faults
193	            // route to the VM server, which gates them on its region table. The
194	            // kernel `heap_window` fast path stays unused, so EMPTY.
195	            HeapWindow::EMPTY,
196	        );
197	    }
198	
199	    // 4. Install priv slots — unchanged from slice 2.6.
200	    // SAFETY: single-threaded boot; sequential mutable borrows on
201	    // priv-table slots 16, 17, 18.
202	    unsafe { install_stub_privs() };
203	
204	    // 5. Enqueue all three on the scheduler.
205	    // SAFETY: single-threaded boot; no other PROC_TABLE / RUNQ borrows
206	    // live at this point.
207	    unsafe {
208	        sched::enqueue(STUB_A_PROC_NR);
209	        sched::enqueue(STUB_B_PROC_NR);
210	        sched::enqueue(STUB_C_PROC_NR);
211	        sched::enqueue(STUB_D_PROC_NR);
212	    }
213	
214	    // 6. One-shot diagnostic: dump per-proc (ttbr0_pa, asid) so the
215	    //    boot log proves each stub has its own distinct AS.
216	    //    SAFETY: single-threaded boot; read-only.
217	    unsafe { print_addrspace_summary() };
218	}
219	
220	/// Load the embedded VM server ELF into a fresh address space, prime its
221	/// entry/stack registers, and make it runnable.
222	///
223	/// Unlike the hand-coded stubs (which use ad-hoc proc/priv slots), VM occupies
224	/// its *real* boot slot `VM_PROC_NR`: `proc::init` → `init_boot_image` already
225	/// populated VM's name, priority, endpoint, and privilege slot (`trap_mask =
226	/// SRV_T` → RECEIVE ANY + SEND to any active slot; `k_call_mask` covering
227	/// `SYS_VMCTL`). So this fills in only the address space + EL0 entry state and
228	/// clears the boot `RTS_NO_PRIV` block. No `install_*_priv` helper is needed.
229	///
230	/// The `AddrSpace` is `mem::forget`-ed for the same reason as [`build_stub`]:
231	/// the page-table tree is now owned via `Proc::ttbr0_pa`.
232	///
233	/// SAFETY: single-threaded boot; the only writer of VM's proc slot and the
234	/// frame allocator here. Must run after `mm::init_from_limine_memmap` and
235	/// before `sched::run`.
236	unsafe fn vm_bootstrap() {
237	    use crate::arch::aarch64::uart::Pl011;
238	    use core::fmt::Write;
239	
240	    let mut aspace = AddrSpace::new().expect("VM AddrSpace::new failed");
241	    let ttbr0_pa = aspace.ttbr0_pa;
242	
243	    let entry = crate::boot_image::elf::load_into(crate::boot_image::VM_ELF, &mut aspace)
244	        .expect("VM ELF load failed");
245	
246	    // Stack: one zeroed RW page; SP starts at its top.
247	    let stack_frame = alloc_frame().expect("VM stack frame alloc failed");
248	    aspace
249	        .map_page(VM_STACK_VA, stack_frame.addr(), Prot::RW_DATA)
250	        .expect("map_page(VM stack) failed");
251	
252	    let asid = unsafe { alloc_asid() };
253	
254	    // SAFETY: single-threaded boot; sole borrow of VM's slot.
255	    unsafe {
256	        let p = proc_slot_mut(VM_PROC_NR).expect("VM proc slot in range");
257	        p.regs.elr_el1 = entry;
258	        p.regs.sp_el0 = VM_STACK_VA + PAGE_SIZE as u64;
259	        p.regs.spsr_el1 = STUB_SPSR_EL0;
260	        p.ttbr0_pa = ttbr0_pa;
261	        p.asid = asid;
262	        p.next_ready = None;
263	        // Clear the boot RTS_NO_PRIV: VM now has an address space and can run.
264	        p.rts_flags.store(0, Ordering::Relaxed);
265	
266	        let _ = writeln!(
267	            Pl011::new(),
268	            "[as] vm nr={} ttbr0_pa={:#x} asid={} entry={:#x}",
269	            p.nr.get(),
270	            p.ttbr0_pa,
271	            p.asid,
272	            entry,
273	        );
274	    }
275	
276	    // The page-table tree is durable via `ttbr0_pa`; don't run `destroy`.
277	    core::mem::forget(aspace);
278	
279	    // SAFETY: single-threaded boot; no other PROC_TABLE / RUNQ borrow is live.
280	    unsafe { sched::enqueue(VM_PROC_NR) };
281	}
282	
283	/// Build one stub's address space: allocate L0 + code + stack frames,
284	/// copy the stub blob into the code frame, install RX/RW mappings, and
285	/// write `(ttbr0_pa, asid)` into the proc slot.
286	///
287	/// `aspace` is intentionally `mem::forget`-ed at the end: the page-table
288	/// tree is now owned by the proc (via its `ttbr0_pa`); the kernel will
289	/// only reach into it again via HHDM walks. `AddrSpace::destroy` would
290	/// recursively free every L1/L2/L3 frame plus the L0 root, which is
291	/// exactly what we don't want.
292	///
293	/// SAFETY: single-threaded boot; this is the only writer of `nr`'s proc
294	/// slot. `stub_start..stub_end` must be a valid contiguous rodata range
295	/// in the kernel image; the linker guarantees both.
296	unsafe fn build_stub(
297	    nr: ProcNr,
298	    priv_id: PrivId,
299	    id: u8,
300	    stub_start: *const u8,
301	    stub_end: *const u8,
302	    code_va: u64,
303	    stack_va: u64,
304	    heap_window: HeapWindow,
305	) {
306	    // Per-proc page-table tree. AddrSpace::new allocates and zeroes the
307	    // L0 root via the frame allocator.
308	    let mut aspace = AddrSpace::new().expect("AddrSpace::new failed during userland_bootstrap");
309	    let ttbr0_pa = aspace.ttbr0_pa;
310	
311	    // Code frame: allocate, copy stub bytes in via HHDM, flush I-cache,
312	    // map RO + EL0-executable.
313	    let code_frame = alloc_frame().expect("code frame alloc failed during userland_bootstrap");
314	    // SAFETY: stub_start/stub_end are rodata symbols inside the kernel
315	    // image; the new code frame is exclusively ours (just allocated, not
316	    // yet mapped into any AS) and HHDM-mapped.
317	    unsafe { copy_stub_into_frame(code_frame, stub_start, stub_end) };
318	    aspace
319	        .map_page(code_va, code_frame.addr(), Prot::RO_CODE)
320	        .expect("map_page(code) during userland_bootstrap");
321	
322	    // Stack frame: zeroed by `alloc_frame`, mapped RW + EL0-no-execute.
323	    let stack_frame = alloc_frame().expect("stack frame alloc failed during userland_bootstrap");
324	    aspace
325	        .map_page(stack_va, stack_frame.addr(), Prot::RW_DATA)
326	        .expect("map_page(stack) during userland_bootstrap");
327	
328	    // Hand the AddrSpace's root over to the proc slot.
329	    // SAFETY: single-threaded boot; this is the only `&mut Proc` borrow
330	    // at this nr right now.
331	    let asid = unsafe { alloc_asid() };
332	    unsafe {
333	        let p = proc_slot_mut(nr).expect("stub proc slot in range");
334	        populate_stub_slot(
335	            p,
336	            nr,
337	            priv_id,
338	            id,
339	            code_va,
340	            stack_va + PAGE_SIZE as u64,
341	            ttbr0_pa,
342	            asid,
343	            heap_window,
344	        );
345	    }
346	
347	    // The page-table tree is durable via `ttbr0_pa`. Drop the AddrSpace
348	    // value without running its (no-op-today, but defensively forget'd)
349	    // destructor — leaving `AddrSpace::destroy` reserved for exit/exec
350	    // paths that actually want to tear an AS down.
351	    core::mem::forget(aspace);
352	}
353	
354	/// Copy `[stub_start, stub_end)` into `frame` (resolved via HHDM) and
355	/// flush the I-cache so the upcoming EL0 fetch sees the new bytes.
356	///
357	/// SAFETY: `frame` must be exclusively owned (not yet mapped anywhere)
358	/// and the HHDM mapping for its PA must be live. `stub_start..stub_end`
359	/// must be a valid byte range in the kernel image.
360	unsafe fn copy_stub_into_frame(frame: Frame, stub_start: *const u8, stub_end: *const u8) {
361	    // SAFETY: end >= start by linker layout; offset_from is well-defined
362	    // on a single rodata symbol pair.
363	    let len = unsafe { stub_end.offset_from(stub_start) } as usize;
364	    assert!(len > 0 && len <= PAGE_SIZE);
365	    // SAFETY: caller's invariants hold; we have the sole pointer to this
366	    // frame, and HHDM is the only mapping.
367	    unsafe {
368	        let dst = phys_to_hhdm(frame.addr()) as *mut u8;
369	        core::ptr::copy_nonoverlapping(stub_start, dst, len);
370	        flush_icache_range(dst as u64, len);
371	    }
372	}
373	
374	/// Write all per-stub fields into `p`. Extends slice 2.5's helper with
375	/// `ttbr0_pa` and `asid` — the rest mirrors slice 2.6.
376	fn populate_stub_slot(
377	    p: &mut Proc,
378	    nr: ProcNr,
379	    priv_id: PrivId,
380	    id: u8,
381	    entry_va: u64,
382	    stack_top: u64,
383	    ttbr0_pa: u64,
384	    asid: u8,
385	    heap_window: HeapWindow,
386	) {
387	    // Name: `id` followed by "-stub\0..." padding. Lets the clock tick
388	    // handler print `name[0]` to identify which stub is running.
389	    p.name = [0; 16];
390	    p.name[0] = id;
391	    p.name[1] = b'-';
392	    p.name[2] = b's';
393	    p.name[3] = b't';
394	    p.name[4] = b'u';
395	    p.name[5] = b'b';
396	
397	    p.nr = nr;
398	    p.endpoint = boot_endpoint(nr);
399	    p.priv_id = Some(priv_id);
400	    p.priority = crate::proc::table::SRV_Q;
401	    // 5 ticks per quantum = 50 ms at 100 Hz.
402	    p.quantum_ms = 5;
403	    p.quantum_left = p.quantum_ms as u64;
404	
405	    // EL0 entry state.
406	    p.regs.elr_el1 = entry_va;
407	    p.regs.sp_el0 = stack_top;
408	    p.regs.spsr_el1 = STUB_SPSR_EL0;
409	
410	    // Per-proc address space. Stored on the slot; the scheduler reads
411	    // both on every EL1 → EL0 transition.
412	    p.ttbr0_pa = ttbr0_pa;
413	    p.asid = asid;
414	
415	    // Kernel-resolved heap window (slice 3.2). Empty for A/B/C.
416	    p.page_fault_state = crate::proc::PageFaultState::EMPTY;
417	    p.heap_window = heap_window;
418	
419	    // Run-queue link starts cleared — `sched::enqueue` sets it.
420	    p.next_ready = None;
421	
422	    // Mark runnable.
423	    p.rts_flags.store(0, Ordering::Relaxed);
424	}
425	
426	/// Install priv slots for A, B, C. Unchanged from slice 2.6.
427	///
428	/// SAFETY: single-threaded boot; touches priv-table slots 16, 17, 18
429	/// sequentially.
430	unsafe fn install_stub_privs() {
431	    // SAFETY: sequential mutable borrow.
432	    unsafe {
433	        install_one_stub_priv(STUB_A_PRIV_ID, STUB_A_PROC_NR, STUB_B_PRIV_ID);
434	    }
435	    // SAFETY: A's borrow has been dropped.
436	    unsafe {
437	        install_one_stub_priv(STUB_B_PRIV_ID, STUB_B_PROC_NR, STUB_A_PRIV_ID);
438	    }
439	    // SAFETY: B's borrow has been dropped.
440	    unsafe {
441	        install_stub_c_priv();
442	    }
443	    // SAFETY: C's borrow has been dropped.
444	    unsafe {
445	        install_stub_d_priv();
446	    }
447	}
448	
449	/// Install stub C's priv slot. Differs from the A/B helper: trap_mask =
450	/// USR_T (SENDREC only), ipc_to opened just to SYSTEM, k_call_mask
451	/// opened just to `SYS_GETINFO`.
452	///
453	/// SAFETY: single-threaded boot; mutates only priv-table slot
454	/// `STUB_C_PRIV_ID`.
455	unsafe fn install_stub_c_priv() {
456	    let system_priv_id = {
457	        // SAFETY: read-only snapshot; no live `&mut Proc` here.
458	        let table = unsafe { proc_table_ref() };
459	        let idx = proc_index(SYSTEM).expect("SYSTEM in proc table");
460	        table[idx]
461	            .priv_id
462	            .expect("SYSTEM priv populated by proc::init")
463	    };
464	
465	    // SAFETY: priv index in-range; no overlapping reference held.
466	    let pr: &mut Priv =
467	        unsafe { priv_slot_mut(STUB_C_PRIV_ID).expect("stub C priv slot in range") };
468	    pr.id = STUB_C_PRIV_ID;
469	    pr.proc_nr = Some(STUB_C_PROC_NR);
470	    pr.flags = SYS_PROC | BILLABLE | PREEMPTIBLE;
471	    pr.trap_mask = USR_T;
472	    pr.ipc_to.fill(0);
473	    set_sys_bit(&mut pr.ipc_to, system_priv_id);
474	    pr.k_call_mask.fill(0);
475	    set_call_bit(&mut pr.k_call_mask, (SYS_GETINFO - KERNEL_CALL) as usize);
476	    pr.notify_pending.fill(0);
477	    pr.asyn_pending.fill(0);
478	    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
479	}
480	
481	/// Install stub D's priv slot (slice 3.5/3.6). D drives `brk` and, since slice
482	/// 3.6, `mmap`/`munmap`: it issues `VM_BRK` / `VM_MMAP` / `VM_MUNMAP` SENDRECs to
483	/// the VM server, then touches the regions it created. All three ride the same
484	/// D→VM edge, so D gets `trap_mask = USR_T` (SENDREC only, like stub C) with
485	/// `ipc_to` opened to VM's priv slot and nothing else. `k_call_mask` stays
486	/// empty — D never calls the kernel directly; it talks to VM, and its page
487	/// faults reach VM via the kernel (`mini_pf_send`, which performs no permission
488	/// check).
489	///
490	/// VM's own `ipc_to` was filled by `init_boot_image` only for the active boot
491	/// priv slots `[0, n_active)` (≈ 0..15); stub D's slot is 19, so VM cannot
492	/// reply to D's SENDREC out of the box. This helper also opens that reverse
493	/// direction (VM → D) as a separate, sequential priv-slot borrow.
494	///
495	/// SAFETY: single-threaded boot; mutates priv-table slots `STUB_D_PRIV_ID`
496	/// and VM's slot, one mutable borrow at a time.
497	unsafe fn install_stub_d_priv() {
498	    // Resolve VM's priv id from a read-only snapshot (mirrors stub C resolving
499	    // SYSTEM). No live `&mut Proc`/`&mut Priv` is held here.
500	    let vm_priv_id = {
501	        let table = unsafe { proc_table_ref() };
502	        let idx = proc_index(VM_PROC_NR).expect("VM in proc table");
503	        table[idx].priv_id.expect("VM priv populated by proc::init")
504	    };
505	
506	    // Stub D's own priv slot: SENDREC to VM, nothing else.
507	    // SAFETY: priv index in-range; no overlapping reference held.
508	    {
509	        let pr: &mut Priv =
510	            unsafe { priv_slot_mut(STUB_D_PRIV_ID).expect("stub D priv slot in range") };
511	        pr.id = STUB_D_PRIV_ID;
512	        pr.proc_nr = Some(STUB_D_PROC_NR);
513	        pr.flags = SYS_PROC | BILLABLE | PREEMPTIBLE;
514	        pr.trap_mask = USR_T;
515	        pr.ipc_to.fill(0);
516	        set_sys_bit(&mut pr.ipc_to, vm_priv_id);
517	        pr.k_call_mask.fill(0);
518	        pr.notify_pending.fill(0);
519	        pr.asyn_pending.fill(0);
520	        pr.sig_mgr = boot_endpoint(RS_PROC_NR);
521	    }
522	
523	    // Open VM → D so VM can reply to D's SENDREC. Separate borrow: D's `&mut
524	    // Priv` above has been dropped.
525	    // SAFETY: priv index in-range; no overlapping reference held.
526	    {
527	        let vm_pr: &mut Priv = unsafe { priv_slot_mut(vm_priv_id).expect("VM priv slot in range") };
528	        set_sys_bit(&mut vm_pr.ipc_to, STUB_D_PRIV_ID);
529	    }
530	}
531	
532	/// Set the per-stub priv slot. `peer_priv_id` is the only target the
533	/// stub is permitted to send/notify (encoded as a single bit in
534	/// `ipc_to`).
535	///
536	/// SAFETY: single-threaded boot; mutates only the priv slot at `id`.
537	unsafe fn install_one_stub_priv(id: PrivId, owner: ProcNr, peer_priv_id: PrivId) {
538	    // SAFETY: priv index in-range; no overlapping reference held.
539	    let pr: &mut Priv = unsafe { priv_slot_mut(id).expect("stub priv slot in range") };
540	    pr.id = id;
541	    pr.proc_nr = Some(owner);
542	    pr.flags = SYS_PROC | BILLABLE | PREEMPTIBLE;
543	    pr.trap_mask = SRV_T;
544	    pr.ipc_to.fill(0);
545	    set_sys_bit(&mut pr.ipc_to, peer_priv_id);
546	    pr.k_call_mask.fill(0);
547	    pr.notify_pending.fill(0);
548	    pr.asyn_pending.fill(0);
549	    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
550	}
551	
552	/// Print one line per stub showing its `(ttbr0_pa, asid)`. Run once at
553	/// the end of `userland_bootstrap`; proves each stub has a distinct
554	/// per-proc address space.
555	///
556	/// SAFETY: single-threaded boot; read-only borrows on proc slots 11/12/13/14.
557	unsafe fn print_addrspace_summary() {
558	    use crate::arch::aarch64::uart::Pl011;
559	    use core::fmt::Write;
560	    let mut uart = Pl011::new();
561	    let _ = writeln!(uart);
562	    for &nr in &[
563	        STUB_A_PROC_NR,
564	        STUB_B_PROC_NR,
565	        STUB_C_PROC_NR,
566	        STUB_D_PROC_NR,
567	    ] {
568	        // SAFETY: sequential read-only borrow of the slot; no other
569	        // reference held while we read.
570	        let p = unsafe { proc_slot_mut(nr).expect("stub slot in range") };
571	        let _ = writeln!(
572	            uart,
573	            "[as] stub {} nr={} ttbr0_pa={:#x} asid={}",
574	            p.name[0] as char,
575	            p.nr.get(),
576	            p.ttbr0_pa,
577	            p.asid,
578	        );
579	    }
580	}
581

