1	// SPDX-License-Identifier: BSD-3-Clause
2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	//! Process counts and well-known endpoints.
4	//!
5	//! Kernel tasks (`ASYNCM`, `IDLE`, `CLOCK`, `SYSTEM`, `HARDWARE`) live at
6	//! negative process numbers; system servers and other user-space processes
7	//! live at non-negative process numbers in the order they boot. The set of
8	//! kernel tasks follows MINIX 3 `include/minix/com.h`; the user-space proc
9	//! numbering does not — see the boot-image section below.
10	
11	use crate::endpoint::{ENDPOINT_SLOT_TOP, Endpoint, ProcNr, make_endpoint};
12	
13	/// Number of kernel tasks (slots with negative proc-numbers).
14	pub const NR_TASKS: usize = 5;
15	/// Number of user-process slots in the process table.
16	pub const NR_PROCS: usize = 1024;
17	/// Number of slots in the privilege table — system (privileged) processes.
18	pub const NR_SYS_PROCS: usize = 64;
19	
20	// NR_PROCS must not grow into the sentinel range (ANY/NONE/SELF live at
21	// ENDPOINT_SLOT_TOP, -1, -2). Raising NR_PROCS past this bound would alias
22	// a real endpoint with a sentinel.
23	const _: () = assert!(NR_PROCS < (ENDPOINT_SLOT_TOP.get() as usize) - 2);
24	
25	// ---------------------------------------------------------------------------
26	// Kernel tasks — negative proc-numbers.
27	// ---------------------------------------------------------------------------
28	
29	/// Asynchronous-message driver (kernel pseudo-task).
30	pub const ASYNCM: ProcNr = ProcNr::new(-5);
31	/// Idle task (runs when nothing else is runnable).
32	pub const IDLE: ProcNr = ProcNr::new(-4);
33	/// Clock task (kernel pseudo-task for timer-driven work).
34	pub const CLOCK: ProcNr = ProcNr::new(-3);
35	/// System task (handles `SYS_*` kernel calls).
36	pub const SYSTEM: ProcNr = ProcNr::new(-2);
37	/// Hardware-interrupt pseudo-task (source endpoint for IRQ notifications).
38	pub const HARDWARE: ProcNr = ProcNr::new(-1);
39	
40	// ---------------------------------------------------------------------------
41	// Well-known user-space servers — generation 0 at boot.
42	//
43	// minix.rs boot image: renumbered contiguously from 0. Differs from MINIX
44	// 3, which scatters slots (no slot 7) and places SCHED at 4. LOG is not
45	// statically slotted in minix.rs — RS spawns it on demand.
46	// ---------------------------------------------------------------------------
47	
48	pub const PM_PROC_NR: ProcNr = ProcNr::new(0);
49	pub const VFS_PROC_NR: ProcNr = ProcNr::new(1);
50	pub const RS_PROC_NR: ProcNr = ProcNr::new(2);
51	pub const MEM_PROC_NR: ProcNr = ProcNr::new(3);
52	pub const TTY_PROC_NR: ProcNr = ProcNr::new(4);
53	pub const DS_PROC_NR: ProcNr = ProcNr::new(5);
54	pub const MFS_PROC_NR: ProcNr = ProcNr::new(6);
55	pub const VM_PROC_NR: ProcNr = ProcNr::new(7);
56	pub const PFS_PROC_NR: ProcNr = ProcNr::new(8);
57	pub const SCHED_PROC_NR: ProcNr = ProcNr::new(9);
58	pub const INIT_PROC_NR: ProcNr = ProcNr::new(10);
59	
60	/// One past the highest boot-server proc-number (`init` is the last slot
61	/// allocated from the boot image).
62	pub const NR_BOOT_PROCS: usize = (INIT_PROC_NR.get() as usize) + 1;
63	
64	// Compile-time guarantees that the proc tables can hold every boot process.
65	const _: () = assert!(NR_PROCS >= NR_BOOT_PROCS);
66	const _: () = assert!(NR_SYS_PROCS >= NR_BOOT_PROCS);
67	
68	/// Build a boot-time endpoint (generation 0) for a task or server.
69	pub const fn boot_endpoint(p: ProcNr) -> Endpoint {
70	    make_endpoint(0, p)
71	}
72	
73	#[cfg(test)]
74	mod tests {
75	    use super::*;
76	    use crate::endpoint::{endpoint_gen, endpoint_proc};
77	
78	    #[test]
