7	use minixrs_kernel_shared::callnr::{GET_WHOAMI, SYS_GETINFO, SYS_GETINFO_NAME_LEN};
8	use minixrs_kernel_shared::com::{RS_PROC_NR, SYSTEM, boot_endpoint};
