13	use crate::init::SefInitCb;
14	use crate::signal::SefSignalCb;
15	
16	/// Callbacks a server registers with the framework at startup. Both are
17	/// optional: a server with no init work or no signal handling passes `None`.
18	pub struct SefConfig {
19	    /// Run once after the startup handshake (see [`SefInitCb`]).
20	    pub init_fresh: Option<SefInitCb>,
21	    /// Invoked for each delivered signal (see [`SefSignalCb`]).
22	    pub signal_handler: Option<SefSignalCb>,
23	}
24	
25	/// A live SEF session, returned by [`sef_startup`]. Carries the server's own
26	/// endpoint + name (learned via `GET_WHOAMI`) and its registered callbacks, so
27	/// [`Sef::receive`] needs no static state. Cheap to copy (an endpoint, a 16-byte
28	/// name, and a function pointer).
29	#[derive(Copy, Clone)]
30	pub struct Sef {
31	    endpoint: Endpoint,
32	    name: [u8; SYS_GETINFO_NAME_LEN],
33	    signal_handler: Option<SefSignalCb>,
34	}
35	
36	/// Perform the SEF startup handshake: learn the server's own endpoint and name
37	/// from the kernel via `SYS_GETINFO(GET_WHOAMI)` (a SENDREC to `SYSTEM`), then
38	/// run the registered fresh-init callback. Returns the [`Sef`] handle to drive
39	/// the receive loop, or a negative error code if the handshake or init failed.
40	pub fn sef_startup(cfg: SefConfig) -> Result<Sef, i32> {
41	    // SYS_GETINFO(GET_WHOAMI): request selector goes in payload[0..4]; the
42	    // kernel replies in-place with our endpoint (0..4), priv flags (4..8),
43	    // init flags (8..12), and name (12..28), setting m_type = OK.
44	    let mut msg = Message {
45	        m_source: 0,
46	        m_type: SYS_GETINFO,
47	        payload: [0u8; 96],
48	    };
49	    msg.payload[0..4].copy_from_slice(&GET_WHOAMI.to_ne_bytes());
50	
51	    let trap_rc = ipc_sendrec(boot_endpoint(SYSTEM), &mut msg);
52	    if trap_rc != OK {
53	        return Err(trap_rc);
54	    }
55	    if msg.m_type != OK {
56	        return Err(msg.m_type);
57	    }
58	
59	    let endpoint = i32::from_ne_bytes(
60	        msg.payload[0..4]
61	            .try_into()
62	            .expect("payload is at least 4 bytes"),
63	    );
64	    let mut name = [0u8; SYS_GETINFO_NAME_LEN];
65	    name.copy_from_slice(&msg.payload[12..12 + SYS_GETINFO_NAME_LEN]);
66	
67	    let sef = Sef {
68	        endpoint,
69	        name,
70	        signal_handler: cfg.signal_handler,
71	    };
72	
73	    if let Some(init) = cfg.init_fresh {
74	        let rc = init(endpoint, &name);
75	        if rc != OK {
76	            return Err(rc);
77	        }
78	    }
79	
80	    Ok(sef)
81	}
82	
83	impl Sef {
84	    /// This server's own endpoint, as learned at startup.
85	    pub fn endpoint(&self) -> Endpoint {
86	        self.endpoint
87	    }
88	
89	    /// This server's name (NUL-padded), as learned at startup.
90	    pub fn name(&self) -> &[u8; SYS_GETINFO_NAME_LEN] {
91	        &self.name
92	    }
93	
94	    /// Receive the next *application* message into `msg`, transparently handling
95	    /// any SEF control messages that arrive first. Returns `OK` (0) once an
96	    /// application message is in `msg`, or a negative error code if the
97	    /// underlying receive failed (the server typically just loops and retries,
98	    /// matching the old hand-rolled `if ipc_receive(..) != 0 { continue }`).
99	    pub fn receive(&self, msg: &mut Message) -> i32 {
100	        loop {
101	            let rc = ipc_receive(ANY, msg);
102	            if rc != OK {
103	                return rc;
104	            }
105	            match classify(msg) {
106	                SefEvent::Application => return OK,
107	                SefEvent::Ping => {
108	                    // Acknowledge the RS heartbeat. A deferred notify still
109	                    // returns OK; any error just means RS re-pings later, so we
110	                    // ignore the result and wait for the next message.
111	                    //
112	                    // TODO(phase 4, RS heartbeat): this ack needs the server's
113	                    // own `ipc_to` bit for RS to be open (cf. `install_stub_d_priv`
114	                    // opening VM→D). Until RS actually pings, that reverse edge is
115	                    // unwired, so the ack would return `ECALLDENIED` — harmless
116	                    // while the heartbeat is dormant, but the wiring must land
117	                    // with the heartbeat or RS will conclude the server is dead.
118	                    let _ = ipc_notify(boot_endpoint(RS_PROC_NR));
119	                }
120	                SefEvent::Signal(signo) => {
121	                    if let Some(handler) = self.signal_handler {
122	                        handler(signo);
123	                    }
124	                }
125	                SefEvent::Init => {
126	                    // Fresh init already ran in sef_startup; the minimal
127	                    // Phase-4 SEF has nothing to do for a re-init request.
128	                    //
129	                    // TODO(phase 4, RS-driven re-init): nail down the reply
130	                    // contract before RS sends this. If RS issues SEF_INIT as a
131	                    // SENDREC it blocks until the server replies — this arm would
132	                    // then have to send an ack or RS hangs. Nothing sends SEF_INIT
133	                    // yet, so swallowing it is correct for now. The same caveat
134	                    // applies to a SENDREC-delivered SEF_SIGNAL.
135	                }
136	            }
137	        }
138	    }
