1	// SPDX-License-Identifier: BSD-3-Clause
2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	//! minix.rs VM (virtual memory) server.
4	//!
5	//! The first *real* user-space process (introduced in slice 3.4a as a build
6	//! milestone). Built as a freestanding aarch64 ELF (see `servers/vm/user.ld`),
7	//! embedded into the kernel image by `kernel/build.rs`, and loaded into its
8	//! own per-process AddrSpace at boot by `arch::aarch64::userland::vm_bootstrap`.
9	//!
10	//! Slice 3.4b made it functional: a `RECEIVE(ANY)` loop that resolves page
11	//! faults. When an EL0 process faults on an unmapped page, the kernel records
12	//! the fault, blocks the faulter on `RTS_PAGEFAULT`, and sends VM a
13	//! `VM_PAGEFAULT` message (`m_source` = faulter, payload = fault addr/flags).
14	//! VM maps a fresh page into the faulter via `SYS_VMCTL(VMCTL_PT_MAP)` and
15	//! unblocks it via `SYS_VMCTL(VMCTL_CLEAR_PAGEFAULT)`. No `alloc` crate — the
16	//! kernel owns the frame allocator; VM only drives policy.
17	//!
18	//! Slice 3.5 adds memory to VM: a per-process [`region`] table and a `VM_BRK`
19	//! request that grows a process's heap region. Page faults are now satisfied
20	//! only when the address lies inside a known region; out-of-region faults take
21	//! a SIGSEGV path (logged, faulter left blocked — real signals are Phase 4).
22	//!
23	//! Slice 3.6 adds `VM_MMAP` / `VM_MUNMAP`: anonymous, VM-chosen regions
24	//! bump-allocated from `MMAP_BASE`. `VM_MMAP` records an `Mmap` region (pages
25	//! fault in lazily, like the heap); `VM_MUNMAP` drops the region and unmaps each
26	//! backing page via `SYS_VMCTL(VMCTL_PT_UNMAP)`.
27	//!
28	//! Slice 4.1 moves the loop scaffolding onto the SEF framework
29	//! ([`minixrs_server_rt`]): `sef_startup` performs the `GET_WHOAMI` handshake
30	//! and `sef.receive` filters SEF control messages, replacing the hand-rolled
31	//! `RECEIVE(ANY)` loop. The request handlers below are unchanged — VM is the
32	//! first real consumer of `server-rt`, proving it before new servers depend
33	//! on it.
34	
35	// Freestanding for the real (bare-metal) build, but a normal host binary under
36	// `cargo test` so `region`'s logic gets host-runnable unit tests. The test
37	// harness needs `std` and its own entry point, so `no_std`/`no_main` and the
38	// `_start` shim below are all gated to `not(test)`.
39	#![cfg_attr(not(test), no_std)]
40	#![cfg_attr(not(test), no_main)]
41	
42	mod region;
43	
44	use minixrs_ipc::{ipc_send, ipc_sendrec};
45	use minixrs_kernel_shared::Message;
46	use minixrs_kernel_shared::callnr::{
47	    SYS_VMCTL, VM_BRK, VM_MMAP, VM_MUNMAP, VM_PAGEFAULT, VMCTL_CLEAR_PAGEFAULT, VMCTL_PROT_WRITE,
48	    VMCTL_PT_MAP, VMCTL_PT_UNMAP,
49	};
50	use minixrs_kernel_shared::com::{SYSTEM, boot_endpoint};
51	use minixrs_kernel_shared::endpoint::{Endpoint, endpoint_proc};
52	use minixrs_kernel_shared::error::OK;
53	use minixrs_server_rt::{SefConfig, sef_startup};
54	
55	/// aarch64 4 KiB page size — VM only needs to page-align fault addresses.
56	const PAGE_SIZE: u64 = 4096;
57	
58	/// ELF entry point. The kernel primes `SP_EL0` before `eret`, so `_start`
59	/// can dive straight into Rust without setting up a stack itself.
60	// Gate the whole shim to `not(test)`: under `cargo test` the crate links as a
61	// normal host executable, and an exported `_start` would collide with the C
62	// runtime's `_start` (a hard "duplicate symbol" error on the GNU/Linux linker).
63	#[cfg(not(test))]
64	#[unsafe(no_mangle)]
65	// `.text._start` is an ELF section name; gate it to the bare-metal target so
66	// `cargo check --workspace` on a Mach-O host (which rejects the specifier)
67	// still type-checks this crate. `ENTRY(_start)` in user.ld roots the symbol
68	// either way, so ordering it first in `.text` is a nicety, not a requirement.
69	#[cfg_attr(target_os = "none", unsafe(link_section = ".text._start"))]
70	pub extern "C" fn _start() -> ! {
71	    main()
72	}
73	
74	// Only `_start` calls `main`; under `cargo test` `_start` is gone, so `main`
75	// (and the message helpers it alone reaches) would read as dead code.
76	#[cfg_attr(test, allow(dead_code))]
77	fn main() -> ! {
78	    // Drive the loop through the SEF framework (slice 4.1): `sef_startup` learns
79	    // VM's endpoint/name via SYS_GETINFO(GET_WHOAMI) and `sef.receive` strips
80	    // SEF control messages, handing back only application requests. VM has no
81	    // init work yet (it will publish its endpoint to DS in slice 4.2) and no
82	    // signal handling, so both callbacks are `None`. If the startup handshake
83	    // fails there is no recovery and nothing to print from EL0 — park forever.
84	    let sef = sef_startup(SefConfig {
85	        init_fresh: None,
86	        signal_handler: None,
87	    })
88	    .unwrap_or_else(|_| {
89	        loop {
90	            core::hint::spin_loop()
91	        }
92	    });
93	
94	    let system = boot_endpoint(SYSTEM);
95	    let mut msg = Message {
96	        m_source: 0,
97	        m_type: 0,
98	        payload: [0u8; 96],
99	    };
100	    loop {
101	        if sef.receive(&mut msg) != 0 {
102	            continue;
103	        }
104	        match msg.m_type {
105	            VM_PAGEFAULT => handle_pagefault(system, msg.m_source, rd_u64(&msg, 0)),
106	            VM_BRK => handle_brk(&mut msg),
107	            VM_MMAP => handle_mmap(&mut msg),
108	            VM_MUNMAP => handle_munmap(system, &mut msg),
109	            // Unknown request: drop it.
110	            _ => {}
111	        }
112	    }
113	}
114	
115	/// Resolve a page fault for `faulting_e` at `far`.
116	///
117	/// Slice 3.5 gates this on the faulter's [`region`] table: only faults inside a
118	/// known region (today, the heap) are satisfied. A fault outside every region
119	/// is a SIGSEGV — VM returns without mapping or clearing, leaving the faulter
120	/// blocked on `RTS_PAGEFAULT` (the only "kill" available until PM + signals in
121	/// Phase 4). VM cannot print from EL0, so this path is silent; the symptom is a
122	/// process that stops making progress.
123	fn handle_pagefault(system: Endpoint, faulting_e: Endpoint, far: u64) {
124	    let nr = endpoint_proc(faulting_e).get();
125	    if !region::contains(nr, far) {
126	        // SIGSEGV: unmapped access outside any region. Leave it blocked.
127	        return;
128	    }
129	
130	    let page = far & !(PAGE_SIZE - 1);
131	
132	    // SYS_VMCTL(VMCTL_PT_MAP, target=faulting_e, vaddr=page, prot=WRITE).
133	    // The kernel allocates + maps the frame; we ignore the returned PA — the
134	    // region table records the VA range, and the kernel owns the frames.
135	    let mut m = Message {
136	        m_source: 0,
137	        m_type: SYS_VMCTL,
138	        payload: [0u8; 96],
139	    };
140	    wr_i32(&mut m, 0, VMCTL_PT_MAP);
141	    wr_i32(&mut m, 4, faulting_e);
142	    wr_u64(&mut m, 8, page);
143	    wr_i32(&mut m, 16, VMCTL_PROT_WRITE);
144	    let _ = ipc_sendrec(system, &mut m);
145	
146	    // SYS_VMCTL(VMCTL_CLEAR_PAGEFAULT, target=faulting_e) — unblock the faulter.
147	    let mut m = Message {
148	        m_source: 0,
149	        m_type: SYS_VMCTL,
150	        payload: [0u8; 96],
151	    };
152	    wr_i32(&mut m, 0, VMCTL_CLEAR_PAGEFAULT);
153	    wr_i32(&mut m, 4, faulting_e);
154	    let _ = ipc_sendrec(system, &mut m);
155	}
156	
157	/// Handle a `VM_BRK` request: set the caller's program break, growing or
158	/// creating its heap region. No frames are mapped here — pages fault in lazily
159	/// and are then satisfied by [`handle_pagefault`] via the region check. Reply
160	/// to the caller (it issued a SENDREC) with `m_type = OK` and the resulting
161	/// break in payload `0..8`, or the negative error in `m_type`.
162	fn handle_brk(msg: &mut Message) {
163	    let caller_e = msg.m_source;
164	    let nr = endpoint_proc(caller_e).get();
165	    let new_break = rd_u64(msg, 0);
166	
167	    let reply_type = match region::set_brk(nr, new_break) {
168	        Ok(brk) => {
169	            wr_u64(msg, 0, brk);
170	            OK
171	        }
172	        Err(e) => e,
173	    };
174	
175	    msg.m_type = reply_type;
176	    msg.m_source = 0; // kernel overwrites on delivery
177	    let _ = ipc_send(caller_e, msg);
178	}
179	
180	/// Handle a `VM_MMAP` request: allocate an anonymous region of `len` bytes
181	/// (payload `0..8`), letting VM choose the base address. No frames are mapped
182	/// here — pages fault in lazily and are satisfied by [`handle_pagefault`] via
183	/// the region check. Reply (the caller issued a SENDREC) with `m_type = OK` and
184	/// the chosen base in payload `0..8`, or the negative error in `m_type`.
185	fn handle_mmap(msg: &mut Message) {
186	    let caller_e = msg.m_source;
187	    let nr = endpoint_proc(caller_e).get();
188	    let len = rd_u64(msg, 0);
189	
190	    let reply_type = match region::mmap(nr, len) {
191	        Ok(addr) => {
192	            wr_u64(msg, 0, addr);
193	            OK
194	        }
195	        Err(e) => e,
196	    };
197	
198	    msg.m_type = reply_type;
199	    msg.m_source = 0; // kernel overwrites on delivery
200	    let _ = ipc_send(caller_e, msg);
201	}
202	
203	/// Handle a `VM_MUNMAP` request: drop the caller's mmap region based at `addr`
204	/// (payload `0..8`) covering `len` bytes (payload `8..16`), then unmap each
205	/// backing page. [`region::munmap`] returns the page-aligned `[start, end)`
206	/// snapshot to sweep and marks the slot free *before* we touch the page tables,
207	/// so the loop runs off owned values, not a re-read of the region. A page that
208	/// never faulted in was never mapped, so the kernel returns `EINVAL` for it —
209	/// harmless, ignored (same as unmapping a hole). Reply with `m_type = OK`, or
210	/// `EINVAL` if no region matched (nothing is unmapped in that case).
211	fn handle_munmap(system: Endpoint, msg: &mut Message) {
212	    let caller_e = msg.m_source;
213	    let nr = endpoint_proc(caller_e).get();
214	    let addr = rd_u64(msg, 0);
215	    let len = rd_u64(msg, 8);
216	
217	    let reply_type = match region::munmap(nr, addr, len) {
218	        Ok((start, end)) => {
219	            let mut page = start;
220	            while page < end {
221	                let mut m = Message {
222	                    m_source: 0,
223	                    m_type: SYS_VMCTL,
224	                    payload: [0u8; 96],
225	                };
226	                wr_i32(&mut m, 0, VMCTL_PT_UNMAP);
227	                wr_i32(&mut m, 4, caller_e);
228	                wr_u64(&mut m, 8, page);
229	                // Ignore the result: a never-faulted page is EINVAL, harmless.
230	                let _ = ipc_sendrec(system, &mut m);
231	                page += PAGE_SIZE;
232	            }
233	            OK
234	        }
235	        Err(e) => e,
236	    };
237	
238	    msg.m_type = reply_type;
239	    msg.m_source = 0; // kernel overwrites on delivery
240	    let _ = ipc_send(caller_e, msg);
241	}
242	
243	// Native-endian payload accessors, mirroring the kernel's `do_vmctl` reads.
244	fn rd_u64(m: &Message, off: usize) -> u64 {
245	    let mut b = [0u8; 8];
246	    b.copy_from_slice(&m.payload[off..off + 8]);
247	    u64::from_ne_bytes(b)
248	}
249	
250	fn wr_i32(m: &mut Message, off: usize, v: i32) {
251	    m.payload[off..off + 4].copy_from_slice(&v.to_ne_bytes());
252	}
253	
254	fn wr_u64(m: &mut Message, off: usize, v: u64) {
255	    m.payload[off..off + 8].copy_from_slice(&v.to_ne_bytes());
256	}
257	
258	// The freestanding panic handler; under `cargo test` std supplies its own.
259	#[cfg(not(test))]
260	#[panic_handler]
261	fn panic(_: &core::panic::PanicInfo) -> ! {
262	    loop {}
263	}
