3	//! Per-process memory regions tracked by the VM server (slice 3.5).
4	//!
5	//! VM is the user-space authority on what virtual addresses a process may
6	//! touch. Before slice 3.5 it resolved *every* page fault by blindly mapping a
7	//! fresh page; now it consults a per-process region table so that only faults
8	//! inside a known region (today: the heap) are satisfied. Out-of-region faults
9	//! are a SIGSEGV (handled by the caller in `main.rs`).
10	//!
11	//! The table is a static `[ClientRegions; MAX_CLIENTS]` indexed by process
12	//! number. This mirrors the kernel's `PROC_TABLE` convention: an
13	//! `UnsafeCell<[T; N]>` inside a `#[repr(transparent)]` newtype with
14	//! `unsafe impl Sync`. The single-mutator invariant is even simpler here than
15	//! in the kernel — VM is a single EL0 thread with no interrupt handlers of its
16	//! own (IRQs trap into the kernel, never into VM), so the table is only ever
17	//! touched from VM's straight-line receive loop.
18	//!
19	//! `MAX_CLIENTS = 16` covers every boot process (proc numbers `0..=15`,
20	//! including stub D at `14`). Phase 4's `fork` will churn proc numbers past
21	//! this cap and revisit the keying; a 1024-slot table (`NR_PROCS`) would burn
22	//! ~512 KiB of BSS — 128 frames the ELF loader would map at boot — for no
23	//! benefit while only the boot stubs exist.
24	
25	use core::cell::UnsafeCell;
26	
27	use minixrs_kernel_shared::error::{EINVAL, ENOMEM};
28	
29	/// Fixed heap origin. Until PM supplies a real per-process memory layout
30	/// (Phase 4), VM and stub D agree on this VA by convention: `brk` grows the
31	/// heap as `[HEAP_BASE, new_break)` and stub D writes inside that range.
32	pub const HEAP_BASE: u64 = 0x0100_0000;
33	
34	/// Origin of the per-process anonymous-mmap arena. VM bump-allocates mmap
35	/// addresses upward from here, so a mapping never collides with stub D's code
36	/// (`0x0043_0000`), stack (`0x0083_0000`), or heap
37	/// (`[0x0100_0000, 0x0100_8000)` today). `0x0200_0000` sits a clean 16 MiB above
38	/// `HEAP_BASE`, leaving the heap room to grow before it could reach the arena.
39	/// The arena itself is bump-only — munmap never returns addresses to it (reuse
40	/// waits for Phase 4's real per-process VM layout), so an unbounded mmap loop
41	/// would eventually walk off the end; acceptable while only the boot stubs run.
42	pub const MMAP_BASE: u64 = 0x0200_0000;
43	
44	/// aarch64 4 KiB page.
45	const PAGE_SIZE: u64 = 4096;
46	
47	/// Proc-number range the table can key. Boot procs are `0..=15`.
48	const MAX_CLIENTS: usize = 16;
49	
50	/// Regions tracked per process: one heap plus a few `mmap` regions in the
51	/// spare slots.
52	const MAX_REGIONS: usize = 4;
53	
54	/// What a region is for. `Unused` marks a free slot.
55	#[derive(Copy, Clone, PartialEq, Eq)]
56	pub enum Kind {
57	    Unused,
58	    Heap,
59	    Mmap,
60	}
61	
62	/// A half-open virtual-address range `[start, end)` and what it backs.
63	#[derive(Copy, Clone)]
64	struct Region {
65	    start: u64,
66	    end: u64,
67	    kind: Kind,
68	}
69	
70	impl Region {
71	    const EMPTY: Self = Self {
72	        start: 0,
73	        end: 0,
74	        kind: Kind::Unused,
75	    };
76	
77	    fn contains(&self, addr: u64) -> bool {
78	        self.kind != Kind::Unused && addr >= self.start && addr < self.end
79	    }
80	}
81	
82	/// One process's region set.
83	#[derive(Copy, Clone)]
84	struct ClientRegions {
85	    regions: [Region; MAX_REGIONS],
86	    /// Next free VA for an anonymous mmap. Bump-only: munmap never returns
87	    /// addresses here (matches a trivial mmap allocator; reuse waits for
88	    /// Phase 4's real VM layout).
89	    mmap_next: u64,
90	}
91	
92	impl ClientRegions {
93	    const EMPTY: Self = Self {
94	        regions: [Region::EMPTY; MAX_REGIONS],
95	        mmap_next: MMAP_BASE,
96	    };
97	
98	    /// True if `addr` falls inside one of this client's regions.
99	    fn contains(&self, addr: u64) -> bool {
100	        self.regions.iter().any(|r| r.contains(addr))
101	    }
102	
103	    /// Set the program break to `new_break`, growing or creating the heap
104	    /// region as `[HEAP_BASE, page_align_up(new_break))`. Returns the resulting
105	    /// break, or `EINVAL` if `new_break` is below `HEAP_BASE`, the page-aligned
106	    /// break would overflow `u64`, or no region slot is free for a new heap.
107	    fn set_brk(&mut self, new_break: u64) -> Result<u64, i32> {
108	        if new_break < HEAP_BASE {
109	            return Err(EINVAL);
110	        }
111	        // page_align_up, guarding the round-up add against wraparound near
112	        // `u64::MAX` (a silent wrap would yield a tiny `end` in `--release`).
113	        let end = new_break
114	            .checked_add(PAGE_SIZE - 1)
115	            .map(|v| v & !(PAGE_SIZE - 1))
116	            .ok_or(EINVAL)?;
117	
118	        // Grow the existing heap region if present.
119	        for r in self.regions.iter_mut() {
120	            if r.kind == Kind::Heap {
121	                r.end = end;
122	                return Ok(end);
123	            }
124	        }
125	        // Otherwise claim a free slot for a fresh heap region.
126	        for r in self.regions.iter_mut() {
127	            if r.kind == Kind::Unused {
128	                *r = Region {
129	                    start: HEAP_BASE,
130	                    end,
131	                    kind: Kind::Heap,
132	                };
133	                return Ok(end);
134	            }
135	        }
136	        Err(EINVAL)
137	    }
138	
139	    /// Allocate an anonymous mmap region of `len` bytes. `len` is rounded up to
140	    /// a whole page; the base address is bump-allocated from `mmap_next`.
141	    /// Returns the chosen base. Errors: `EINVAL` if `len` is 0 or the round-up /
142	    /// bump would overflow `u64`; `ENOMEM` if no region slot is free.
143	    fn mmap(&mut self, len: u64) -> Result<u64, i32> {
144	        if len == 0 {
145	            return Err(EINVAL);
146	        }
147	        // page_align_up, guarding the round-up add against wraparound.
148	        let size = len
149	            .checked_add(PAGE_SIZE - 1)
150	            .map(|v| v & !(PAGE_SIZE - 1))
151	            .ok_or(EINVAL)?;
152	        let start = self.mmap_next;
153	        let end = start.checked_add(size).ok_or(EINVAL)?;
154	
155	        for r in self.regions.iter_mut() {
156	            if r.kind == Kind::Unused {
157	                *r = Region {
158	                    start,
159	                    end,
160	                    kind: Kind::Mmap,
161	                };
162	                self.mmap_next = end;
163	                return Ok(start);
164	            }
165	        }
166	        Err(ENOMEM)
167	    }
168	
169	    /// Unmap the `Mmap` region based at `addr`, marking its slot `Unused` and
170	    /// returning the page-aligned `[start, end)` range whose backing pages the
171	    /// caller must sweep with `VMCTL_PT_UNMAP`. The match is keyed on the region
172	    /// *base*, so an over- or under-stated `len` can never unmap a neighbor; the
173	    /// returned `end` is additionally capped at the region's own `end` so an
174	    /// overstated `len` cannot drive the sweep into the heap and free its
175	    /// frames. `EINVAL` if `len` is 0, no `Mmap` region starts at `addr`, or
176	    /// `len` overflows. Rejecting `len == 0` (as POSIX does, and symmetric with
177	    /// [`mmap`](Self::mmap)) avoids dropping a region's tracking while leaving
178	    /// its already-faulted-in frames mapped and orphaned.
179	    fn munmap(&mut self, addr: u64, len: u64) -> Result<(u64, u64), i32> {
180	        if len == 0 {
181	            return Err(EINVAL);
182	        }
183	        let size = len
184	            .checked_add(PAGE_SIZE - 1)
185	            .map(|v| v & !(PAGE_SIZE - 1))
186	            .ok_or(EINVAL)?;
187	        let end = addr.checked_add(size).ok_or(EINVAL)?;
188	
189	        for r in self.regions.iter_mut() {
190	            if r.kind == Kind::Mmap && r.start == addr {
191	                let sweep_end = end.min(r.end);
192	                *r = Region::EMPTY;
193	                return Ok((addr, sweep_end));
194	            }
195	        }
196	        Err(EINVAL)
197	    }
198	}
199	
200	/// `UnsafeCell`-wrapped static table. See the module-level note for the
201	/// single-mutator invariant that makes the `Sync` impl sound.
202	#[repr(transparent)]
203	struct RegionTable(UnsafeCell<[ClientRegions; MAX_CLIENTS]>);
204	
205	// SAFETY: VM is a single-threaded EL0 process with no interrupt handlers of
206	// its own; the table is only ever accessed from VM's straight-line receive
207	// loop, so there is never concurrent access.
208	unsafe impl Sync for RegionTable {}
209	
210	static TABLE: RegionTable = RegionTable(UnsafeCell::new([ClientRegions::EMPTY; MAX_CLIENTS]));
211	
212	/// In-range proc number → table index, or `None` if `nr` is a kernel task
213	/// (negative) or past the boot cap.
214	fn client_idx(nr: i32) -> Option<usize> {
215	    let idx = usize::try_from(nr).ok()?;
216	    (idx < MAX_CLIENTS).then_some(idx)
217	}
218	
219	/// Borrow the client's region set immutably (read path).
220	fn client_ref(nr: i32) -> Option<&'static ClientRegions> {
221	    let idx = client_idx(nr)?;
222	    // SAFETY: single-mutator invariant (module note); shared read, `idx` in
223	    // range. No `&mut` to the table is live during VM's straight-line loop.
224	    let table = unsafe { &*TABLE.0.get() };
225	    Some(&table[idx])
226	}
227	
228	/// Borrow the client's region set mutably (write path).
229	fn client_mut(nr: i32) -> Option<&'static mut ClientRegions> {
230	    let idx = client_idx(nr)?;
231	    // SAFETY: single-mutator invariant (module note); `idx < MAX_CLIENTS`.
232	    let table = unsafe { &mut *TABLE.0.get() };
233	    Some(&mut table[idx])
234	}
235	
236	/// True if `addr` falls inside one of `nr`'s regions. The VM fault path only
237	/// satisfies faults for which this returns true.
238	pub fn contains(nr: i32, addr: u64) -> bool {
239	    client_ref(nr).is_some_and(|client| client.contains(addr))
240	}
241	
242	/// Set process `nr`'s program break to `new_break`, growing or creating its
243	/// heap region as `[HEAP_BASE, page_align_up(new_break))`. Returns the
244	/// resulting break on success, or `EINVAL` if `nr` is untrackable or
245	/// `new_break` is below `HEAP_BASE`.
246	///
247	/// No frames are mapped here — pages fault in lazily on first touch and are
248	/// resolved through [`contains`] in the fault path.
249	pub fn set_brk(nr: i32, new_break: u64) -> Result<u64, i32> {
250	    client_mut(nr).ok_or(EINVAL)?.set_brk(new_break)
251	}
252	
253	/// Allocate an anonymous mmap region of `len` bytes for process `nr`, with VM
254	/// choosing the base address. Returns the base on success; `EINVAL` if `nr` is
255	/// untrackable or `len` is 0/overflowing; `ENOMEM` if no region slot is free.
256	///
257	/// No frames are mapped here — pages fault in lazily on first touch and are
258	/// resolved through [`contains`] in the fault path.
259	pub fn mmap(nr: i32, len: u64) -> Result<u64, i32> {
260	    client_mut(nr).ok_or(EINVAL)?.mmap(len)
261	}
262	
263	/// Drop process `nr`'s mmap region based at `addr` and return the page-aligned
264	/// `[start, end)` range whose backing pages the caller must unmap. `EINVAL` if
265	/// `nr` is untrackable, `len` is 0, or no `Mmap` region starts at `addr`.
266	pub fn munmap(nr: i32, addr: u64, len: u64) -> Result<(u64, u64), i32> {
267	    client_mut(nr).ok_or(EINVAL)?.munmap(addr, len)
268	}
