272	    use super::*;
273	
274	    #[test]
275	    fn set_brk_creates_heap_region() {
276	        let mut c = ClientRegions::EMPTY;
277	        let brk = c.set_brk(HEAP_BASE + 0x4000).unwrap();
278	        assert_eq!(brk, HEAP_BASE + 0x4000);
279	        assert!(c.contains(HEAP_BASE));
280	        assert!(c.contains(HEAP_BASE + 0x3FFF));
281	        // Half-open: the break itself is the first byte *past* the region.
282	        assert!(!c.contains(HEAP_BASE + 0x4000));
283	        assert!(!c.contains(HEAP_BASE - 1));
284	    }
285	
286	    #[test]
