1	// SPDX-License-Identifier: BSD-3-Clause
2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	// minix.rs Microkernel
4	#![cfg_attr(target_os = "none", no_std)]
5	#![cfg_attr(target_os = "none", no_main)]
6	
7	// The kernel crate is only meaningful on bare-metal targets (`target_os =
8	// "none"`). When `cargo check --workspace` runs against the host target
9	// (macos / linux), we collapse to a no-op `main` so the workspace stays
10	// checkable; the ELF-only `link_section` attributes, the `_start` entry
11	// path, and the panic handler all rely on the bare-metal target.
12	
13	#[cfg(target_os = "none")]
14	mod arch;
15	#[cfg(target_os = "none")]
16	mod boot_image;
17	#[cfg(target_os = "none")]
18	mod clock;
19	#[cfg(target_os = "none")]
20	mod ipc;
21	#[cfg(target_os = "none")]
22	mod mm;
23	#[cfg(target_os = "none")]
24	mod panic;
25	#[cfg(target_os = "none")]
26	mod proc;
27	#[cfg(target_os = "none")]
28	mod system;
29	#[cfg(target_os = "none")]
30	mod uart;
31	
32	#[cfg(target_os = "none")]
33	use core::fmt::Write;
34	
35	/// Scheduler tick rate (Hz). 100 Hz → 10 ms ticks, matching the classic
36	/// MINIX 3 cadence. Combined with the per-stub `quantum_ms = 5`, each task
37	/// gets ~50 ms of CPU before preemption.
38	#[cfg(target_os = "none")]
39	const TICK_HZ: u64 = 100;
40	
41	#[cfg(target_os = "none")]
42	#[unsafe(no_mangle)]
43	extern "C" fn kmain() -> ! {
44	    // Resolve the UART MMIO virtual address before any output. Limine maps
45	    // PL011 into the HHDM (under base revision 2, the [0, 4 GiB) blanket
46	    // map covers device memory); we fall back to the physical address if
47	    // the bootloader didn't populate the response.
48	    let hhdm = arch::limine_hhdm_offset().unwrap_or(0);
49	    arch::set_uart_base(hhdm as usize + arch::PL011_PHYS_BASE);
50	
51	    arch::init();
52	
53	    let mut con = uart::Uart::new();
54	    let _ = writeln!(con, "minix.rs booting on aarch64");
55	
56	    if arch::limine_base_revision_supported() {
57	        let _ = writeln!(con, "HHDM offset: {hhdm:#018x}");
58	    } else {
59	        let _ = writeln!(con, "Limine base revision unsupported (loader is too old)");
60	    }
61	
62	    proc::init();
63	    let _ = writeln!(con);
64	    let _ = proc::dump_tables(&mut con);
65	
66	    // Slice 3.1a: capture Limine's HHDM offset and populate the physical
67	    // frame allocator from the memmap. Both are prerequisites for the
68	    // address-space API (`arch::aarch64::addrspace::AddrSpace`) — which
69	    // slice 3.1b's `userland_bootstrap` now drives in earnest, one
70	    // AddrSpace per EL0 stub.
71	    // SAFETY: single-threaded boot; this is the only writer of HHDM_OFFSET
72	    // and the only initializer of the allocator.
73	    unsafe {
74	        mm::set_hhdm_offset(hhdm);
75	        mm::init_from_limine_memmap();
76	    }
77	
78	    // Slice 2.4: bring up the interrupt controller and timer, populate two
79	    // EL0 stub tasks, enqueue them, and hand control to the scheduler.
80	    // SAFETY: single-threaded boot; DAIF still masked from Limine handoff.
81	    unsafe { arch::aarch64::gic::init() };
82	    // SAFETY: same; gic is configured first so the timer's PPI 27 is routable.
83	    unsafe {
84	        arch::aarch64::gic::enable_ppi(arch::aarch64::timer::INTID_VIRT_TIMER, 0x80);
85	    }
86	    // SAFETY: same; programs CNTV_TVAL_EL0 + CNTV_CTL_EL0.
87	    unsafe { arch::aarch64::timer::init(TICK_HZ) };
88	
89	    let _ = writeln!(
90	        con,
91	        "\nentering EL0 stub tasks (preemption demo: A/B interleaved by timer)..."
92	    );
93	
94	    // SAFETY: single-threaded boot context; no other reference into the
95	    // page-table arena, user pages, or stub proc slots exists. Bootstrap
96	    // populates both stub slots and enqueues them.
97	    unsafe { arch::userland_bootstrap() };
98	
99	    // SAFETY: at least one proc is enqueued (we just enqueued two); first
100	    // eret transitions from EL1 boot context into EL0 user execution.
101	    unsafe { proc::sched::run() }
102	}
103	
104	#[cfg(not(target_os = "none"))]
105	fn main() {}
106

