pub fn check(key: &[u8; KEY_LEN]) -> bool {
    // SAFETY: single-mutator invariant (module note); shared read, no live `&mut`.
    let t = unsafe { &*TABLE.0.get() };
    check_in(t, key)
}

#[cfg(test)]
