1	// SPDX-License-Identifier: BSD-3-Clause
2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	//! Embedded boot-image archive and its loader.
4	//!
5	//! `kernel/build.rs` builds every boot server for the EL0 user target, packs the
6	//! resulting ELFs into a single MXBI archive, and emits `BOOT_IMAGE_PATH`. The
7	//! archive is embedded here as a rodata `&[u8]` via `include_bytes!`. The bytes
8	//! land in the kernel's `.rodata`, which Limine reports under
9	//! `EXECUTABLE_AND_MODULES`, so they are never visible to the frame allocator —
10	//! same model as the hand-coded EL0 stub blobs in `arch/aarch64/user_stub.S`.
11	//!
12	//! Archive layout (slice 4.2; all multi-byte fields little-endian, matching
13	//! `build.rs::pack_mxbi`):
14	//!
15	//! ```text
16	//!   16-byte header: magic "MXBI" (u32), version (u32), entry_count (u32), total_size (u32)
17	//!   entry_count × 32-byte records: { proc_nr:i32, offset:u32, len:u32, name:[u8;20] }
18	//!   then the ELF payloads back-to-back, each at its recorded offset
19	//! ```
20	//!
21	//! [`BootImage`] is a zero-copy view: [`BootImage::iter`] drives the boot loader
22	//! (one [`load_boot_server`](crate::arch::aarch64::userland) call per module),
23	//! and [`BootImage::module_by_name`] is reused by exec in slice 4.7.
24	//!
25	//! NOTE: this whole module is gated on `target_os = "none"` in `main.rs`, so
26	//! `env!("BOOT_IMAGE_PATH")` is only ever evaluated for the bare-metal build —
27	//! host `cargo check`/`cargo test` (where the env var is unset) never compile it.
28	
29	pub mod elf;
30	
31	use minixrs_kernel_shared::ProcNr;
32	
33	/// The packed MXBI boot-image archive, built and embedded by `build.rs`.
34	static BOOT_IMAGE: &[u8] = include_bytes!(env!("BOOT_IMAGE_PATH"));
35	
36	/// "MXBI" as a little-endian `u32` (bytes M, X, B, I).
37	const MXBI_MAGIC: u32 = 0x4942_584D;
38	const MXBI_VERSION: u32 = 1;
39	const HDR_LEN: usize = 16;
40	const REC_LEN: usize = 32;
41	const NAME_LEN: usize = 20;
42	
43	/// Zero-copy view over the embedded MXBI archive.
44	pub struct BootImage {
45	    bytes: &'static [u8],
46	    count: usize,
47	}
48	
49	impl BootImage {
50	    /// Borrow the embedded archive, validating its header. Panics at boot on a
51	    /// malformed image — the archive is produced by our own build, so any
52	    /// failure is a build bug (same fatal-at-boot policy as [`elf`]).
53	    pub fn get() -> Self {
54	        let bytes = BOOT_IMAGE;
55	        assert!(bytes.len() >= HDR_LEN, "boot image truncated");
56	        assert!(rd_u32(bytes, 0) == MXBI_MAGIC, "boot image bad magic");
57	        assert!(rd_u32(bytes, 4) == MXBI_VERSION, "boot image bad version");
58	        let count = rd_u32(bytes, 8) as usize;
59	        let total = rd_u32(bytes, 12) as usize;
60	        assert!(
61	            HDR_LEN + count * REC_LEN <= bytes.len() && total <= bytes.len(),
62	            "boot image table out of range"
63	        );
64	        Self { bytes, count }
65	    }
66	
67	    /// Decode record `i` into `(proc_nr, name, elf)`. The `name` is the
68	    /// NUL-trimmed record name; `elf` is the payload subslice.
69	    fn record(&self, i: usize) -> (ProcNr, &'static str, &'static [u8]) {
70	        let rec = HDR_LEN + i * REC_LEN;
71	        let proc_nr = rd_i32(self.bytes, rec);
72	        let offset = rd_u32(self.bytes, rec + 4) as usize;
73	        let len = rd_u32(self.bytes, rec + 8) as usize;
74	
75	        let name_field = &self.bytes[rec + 12..rec + 12 + NAME_LEN];
76	        let nul = name_field.iter().position(|&b| b == 0).unwrap_or(NAME_LEN);
77	        let name = core::str::from_utf8(&name_field[..nul]).unwrap_or("");
78	
79	        let elf = &self.bytes[offset..offset + len];
80	        (ProcNr::new(proc_nr), name, elf)
81	    }
82	
83	    /// Iterate `(proc_nr, elf)` over every module, in archive (load) order.
84	    pub fn iter(&self) -> BootImageIter {
85	        BootImageIter {
86	            bytes: self.bytes,
87	            count: self.count,
88	            idx: 0,
89	        }
90	    }
91	
92	    /// The ELF payload for a boot proc number, or `None`. Symmetric with
93	    /// [`module_by_name`](Self::module_by_name).
94	    #[allow(dead_code)] // used by later Phase-4 slices (RS restart, exec)
95	    pub fn module_by_proc_nr(&self, nr: ProcNr) -> Option<&'static [u8]> {
96	        (0..self.count).map(|i| self.record(i)).find_map(
97	            |(p, _, elf)| {
98	                if p == nr { Some(elf) } else { None }
99	            },
100	        )
101	    }
102	
103	    /// The ELF payload for a module name (e.g. `"vfs"`), or `None`. Reused by
104	    /// exec in slice 4.7 to resolve a boot-embedded binary by name.
105	    #[allow(dead_code)] // consumed by slice 4.7 (SYS_EXEC of a boot-embedded binary)
106	    pub fn module_by_name(&self, name: &str) -> Option<&'static [u8]> {
107	        (0..self.count).map(|i| self.record(i)).find_map(
108	            |(_, n, elf)| {
109	                if n == name { Some(elf) } else { None }
110	            },
111	        )
112	    }
113	}
114	
115	/// Iterator over `(proc_nr, elf)` for each module. Holds only `'static` copies,
116	/// so it does not borrow the [`BootImage`].
117	pub struct BootImageIter {
118	    bytes: &'static [u8],
119	    count: usize,
120	    idx: usize,
121	}
122	
123	impl Iterator for BootImageIter {
124	    type Item = (ProcNr, &'static [u8]);
125	
126	    fn next(&mut self) -> Option<Self::Item> {
127	        if self.idx >= self.count {
128	            return None;
129	        }
130	        // Decode in place rather than building a transient BootImage.
131	        let rec = HDR_LEN + self.idx * REC_LEN;
132	        let proc_nr = rd_i32(self.bytes, rec);
133	        let offset = rd_u32(self.bytes, rec + 4) as usize;
134	        let len = rd_u32(self.bytes, rec + 8) as usize;
135	        self.idx += 1;
136	        Some((ProcNr::new(proc_nr), &self.bytes[offset..offset + len]))
137	    }
138	}
139	
140	/// Read a little-endian `u32` at `off`. Panics (via slicing) on a malformed
141	/// archive — fatal at boot, like [`elf`]'s reads.
142	fn rd_u32(b: &[u8], off: usize) -> u32 {
143	    u32::from_le_bytes(b[off..off + 4].try_into().expect("u32 in range"))
144	}
145	
146	/// Read a little-endian `i32` at `off`.
147	fn rd_i32(b: &[u8], off: usize) -> i32 {
148	    i32::from_le_bytes(b[off..off + 4].try_into().expect("i32 in range"))
149	}

1	// SPDX-License-Identifier: BSD-3-Clause
2	// Copyright (c) 2025-2026 Kevin Barnard and minix.rs Contributors
3	// Assembles the per-arch entry path and exception vectors into the kernel.
4	//
5	// .S files go through clang (cross-targeted at the kernel triple) and the
6	// resulting .o files are passed straight to the linker via cargo:rustc-link-arg.
7	// We deliberately *avoid* the cc crate's static-library packaging because the
8	// linker's archive member resolution wouldn't pull in `_start` (it's only
9	// referenced via the linker-script `ENTRY` directive, not from any Rust
10	// symbol). Direct .o linkage sidesteps that, and it also dodges the
11	// macOS-ar/ELF-object mismatch entirely.
12	
13	use std::path::PathBuf;
14	use std::process::Command;
15	
16	fn main() {
17	    // Host builds (cargo check / cargo test on macOS or Linux) compile the
18	    // kernel crate as a no-op (main.rs gates every real module on
19	    // `target_os = "none"`). Skip assembly entirely for those — the ELF .o
20	    // files clang would produce here aren't link-compatible with the
21	    // host's mach-o or glibc-flavored ELF and would only break tests.
22	    let target_os = std::env::var("CARGO_CFG_TARGET_OS").unwrap_or_default();
23	    if target_os != "none" {
24	        return;
25	    }
26	
27	    let arch = std::env::var("CARGO_CFG_TARGET_ARCH").expect("CARGO_CFG_TARGET_ARCH unset");
28	    let out_dir = PathBuf::from(std::env::var_os("OUT_DIR").expect("OUT_DIR unset"));
29	
30	    match arch.as_str() {
31	        "aarch64" => {
32	            let sources = [
33	                "src/arch/aarch64/entry.S",
34	                "src/arch/aarch64/vectors.S",
35	                "src/arch/aarch64/trap.S",
36	                "src/arch/aarch64/interrupt.S",
37	                "src/arch/aarch64/user_stub.S",
38	            ];
39	            for src in &sources {
40	                println!("cargo:rerun-if-changed={src}");
41	                let stem = std::path::Path::new(src)
42	                    .file_stem()
43	                    .unwrap()
44	                    .to_string_lossy();
45	                let obj = out_dir.join(format!("{stem}.o"));
46	                let status = Command::new("clang")
47	                    .args([
48	                        "--target=aarch64-unknown-none",
49	                        "-ffreestanding",
50	                        "-c",
51	                        src,
52	                        "-o",
53	                    ])
54	                    .arg(&obj)
55	                    .status()
56	                    .expect("failed to spawn clang");
57	                if !status.success() {
58	                    panic!("clang failed assembling {src}");
59	                }
60	                println!("cargo:rustc-link-arg={}", obj.display());
61	            }
62	            println!("cargo:rerun-if-changed=src/arch/aarch64/linker.ld");
63	
64	            // Build every boot server as a freestanding EL0 ELF, pack them into
65	            // the MXBI boot-image archive, and emit `BOOT_IMAGE_PATH` for
66	            // `boot_image` to `include_bytes!` (slice 4.2, generalizing the
67	            // slice-3.4 single-VM embed).
68	            build_boot_image(&out_dir);
69	        }
70	        "x86_64" => {
71	            // Phase 8 territory -- nothing to assemble yet.
72	        }
73	        other => panic!("unsupported target arch: {other}"),
74	    }
75	}
76	
77	/// Build every boot server, pack the resulting ELFs into the MXBI boot-image
78	/// archive in `OUT_DIR`, and emit `BOOT_IMAGE_PATH` so `boot_image` can
79	/// `include_bytes!` it (slice 4.2). Generalizes the slice-3.4 single-VM embed.
80	///
81	/// The server list is the single source of truth for which servers boot and at
82	/// which proc number; the proc numbers must match `kernel-shared/src/com.rs`.
83	/// VM is built first so it takes ASID 1 and is enqueued first (its
84	/// `RECEIVE(ANY)` blocks immediately, matching the pre-4.2 boot behavior).
85	fn build_boot_image(out_dir: &std::path::Path) {
86	    let manifest =
87	        PathBuf::from(std::env::var("CARGO_MANIFEST_DIR").expect("CARGO_MANIFEST_DIR unset"));
88	    let workspace = manifest.parent().expect("kernel manifest has no parent");
89	
90	    // Libraries every server links against. Watched once (not per-server) so a
91	    // change re-runs build.rs and re-embeds. `server-rt/src` and
92	    // `kernel-shared/src` are directories so cargo watches every submodule —
93	    // otherwise an edit to e.g. a new DS request number would embed stale ELFs.
94	    for path in [
95	        workspace.join("minix-ipc/src/lib.rs"),
96	        workspace.join("server-rt/src"),
97	        workspace.join("kernel-shared/src"),
98	    ] {
99	        println!("cargo:rerun-if-changed={}", path.display());
100	    }
101	
102	    // (cargo package, crate dir, boot proc number). Proc numbers come from
103	    // `kernel-shared/src/com.rs`; the archive carries them so the loader writes
104	    // the right proc slot.
105	    let servers: [(&str, std::path::PathBuf, i32); 3] = [
106	        ("minixrs-vm", workspace.join("servers/vm"), 7), // VM_PROC_NR
107	        ("minixrs-ds", workspace.join("servers/ds"), 5), // DS_PROC_NR
108	        ("minixrs-vfs", workspace.join("servers/vfs"), 1), // VFS_PROC_NR
109	    ];
110	
111	    let mut modules: Vec<(i32, String, Vec<u8>)> = Vec::with_capacity(servers.len());
112	    for (crate_name, crate_dir, proc_nr) in &servers {
113	        let elf = build_server(crate_name, crate_dir, workspace, out_dir);
114	        let bytes = std::fs::read(&elf)
115	            .unwrap_or_else(|e| panic!("reading {crate_name} ELF {}: {e}", elf.display()));
116	        let name = crate_name.strip_prefix("minixrs-").unwrap_or(crate_name);
117	        modules.push((*proc_nr, name.to_string(), bytes));
118	    }
119	
120	    let archive = pack_mxbi(&modules);
121	    let archive_path = out_dir.join("boot_image.mxbi");
122	    std::fs::write(&archive_path, &archive).expect("writing boot-image archive");
123	    println!("cargo:rustc-env=BOOT_IMAGE_PATH={}", archive_path.display());
124	}
125	
126	/// Build one server crate for the aarch64 EL0 user target and return the path to
127	/// the produced ELF.
128	///
129	/// We reuse the builtin `aarch64-unknown-none` triple but must NOT inherit the
130	/// kernel's linker script: the workspace `.cargo/config.toml` forces
131	/// `-Tkernel/.../linker.ld` on that triple via `rustflags`. We override it with
132	/// `CARGO_ENCODED_RUSTFLAGS` (highest-precedence; replaces config rustflags
133	/// entirely) pointing at the server's `user.ld`, and isolate each build in its
